using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;
    public float damageMultiplier = 1f;
    public float priceMultiplier = 1f;

    private void Update()
    {
        if (Input.GetKeyDown(KeyCode.R))
        {
            TakeDamage(10);
        }
    }

    public void TakeDamage(int amount)
    {
        health -= (int)(amount * damageMultiplier);
        Debug.Log("Health: " + health);
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
        Debug.Log("Currency: " + currency);
    }

    public void BuyItem(string itemName, int price)
    {
        if (currency >= price)
        {
            currency -= price;
            Debug.Log(itemName + " purchased!");
        }
        else
        {
            Debug.Log("Not enough currency to purchase " + itemName);
        }
    }

    private void OnApplicationPause(bool pause)
    {
        if (!pause)
        {
            // Save player stats when game is paused or closed
            PlayerPrefs.SetInt("health", health);
            PlayerPrefs.SetInt("currency", currency);
            PlayerPrefs.Save();
        }
    }

    private void Start()
    {
        // Load player stats from PlayerPrefs
        health = PlayerPrefs.GetInt("health");
        currency = PlayerPrefs.GetInt("currency");

        // Initialize damage and price multipliers
        damageMultiplier = 1f;
        priceMultiplier = 1f;

        // Add event listener for in-app purchases
#if UNITY_IOS || UNITY_ANDROID
        if (Application.platform == RuntimePlatform.IPhonePlayer || Application.platform == RuntimePlatform.Android)
        {
            InAppPurchaseManager.instance.Init();
        }
#endif
    }

    private void OnEnable()
    {
        // Load player stats from PlayerPrefs when game is resumed
        health = PlayerPrefs.GetInt("health");
        currency = PlayerPrefs.GetInt("currency");

        // Initialize damage and price multipliers
        damageMultiplier = 1f;
        priceMultiplier = 1f;

#if UNITY_IOS || UNITY_ANDROID
        if (Application.platform == RuntimePlatform.IPhonePlayer || Application.platform == RuntimePlatform.Android)
        {
            InAppPurchaseManager.instance.Init();
        }
#endif
    }

    private void OnDisable()
    {
        // Save player stats when game is paused or closed
        PlayerPrefs.SetInt("health", health);
        PlayerPrefs.SetInt("currency", currency);
        PlayerPrefs.Save();
    }
}

public class InAppPurchaseManager : MonoBehaviour
{
#if UNITY_IOS || UNITY_ANDROID
    public static InAppPurchaseManager instance;

    private void Awake()
    {
        if (instance == null)
        {
            instance = this;
        }
        else if (instance != this)
        {
            Destroy(gameObject);
        }

        DontDestroyOnLoad(gameObject);
    }

    public void Init()
    {
#if UNITY_IOS
        // Initialize iOS in-app purchases
        StoreKit.Init();
#elif UNITY_ANDROID
        // Initialize Android in-app purchases
        GooglePlayGamesPlatform.Instance.Connect();
#endif
    }
}